import React, { useState } from 'react';
import Layout from './components/Layout';
import { DepartmentId, FormSubmissionStatus, Submodule } from './types';
import { DEPARTMENTS } from './constants';
import { Input, Select, TextArea, FormCard, SuccessMessage, FormMirror } from './components/FormComponents';

const App: React.FC = () => {
  const [activeDept, setActiveDept] = useState<DepartmentId>('home');
  const [activeSubmodule, setActiveSubmodule] = useState<string | null>(null);
  const [status, setStatus] = useState<FormSubmissionStatus>({ submitting: false, success: null, error: null });
  const [formData, setFormData] = useState<Record<string, string>>({});

  const handleNavigate = (deptId: DepartmentId, submoduleId: string | null) => {
    setActiveDept(deptId);
    setActiveSubmodule(submoduleId);
    setStatus({ submitting: false, success: null, error: null });
    setFormData({});
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const generateCopyMessage = () => {
    if (Object.values(formData).every(v => !v)) return "";
    const dataLines = Object.entries(formData).filter(([_, v]) => v).map(([k, v]) => `*${k.replace(/_/g, ' ')}:* ${v}`).join('\n');
    const sub = getAllSubmodules().find(s => s.id === activeSubmodule);
    const header = `📋 *BR CLUBE - ${sub?.name.toUpperCase()}*`;
    return `${header}\n\nOlá! Seguem os dados atualizados:\n\n${dataLines}\n\n_BR Clube - Proteção em todo lugar._`;
  };

  const getAllSubmodules = (): Submodule[] => {
    const subs: Submodule[] = [];
    DEPARTMENTS.forEach(d => {
      subs.push(...d.submodules);
      d.groups?.forEach(g => subs.push(...g.items));
    });
    return subs;
  };

  const simulateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStatus({ submitting: true, success: null, error: null });
    setTimeout(() => setStatus({ submitting: false, success: true, error: null }), 1200);
  };

  const renderHome = () => (
    <div className="space-y-10 animate-in fade-in duration-700">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <div className="flex items-center space-x-2 text-cyan-600 font-bold text-[10px] uppercase tracking-[0.2em] mb-2">
             <span className="w-8 h-[2px] bg-cyan-600"></span>
             <span>BR Desk 4.0</span>
          </div>
          <h1 className="text-3xl lg:text-4xl font-[900] text-slate-800 tracking-tight leading-none">
            Operação <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-500 to-blue-600">Unificada</span>
          </h1>
          <p className="text-slate-500 mt-2 text-base font-medium max-w-lg leading-relaxed">
            Selecione uma categoria abaixo para acessar os serviços operacionais.
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {DEPARTMENTS.map((dept, idx) => (
          <button 
            key={dept.id}
            onClick={() => handleNavigate(dept.id, null)}
            style={{ animationDelay: `${idx * 50}ms` }}
            className="group relative bg-white p-6 rounded-2xl border border-slate-100 shadow-sm hover:shadow-xl hover:shadow-cyan-100/30 hover:-translate-y-1 transition-all duration-300 text-left animate-in fade-in slide-in-from-bottom-2"
          >
            <div className="w-12 h-12 bg-slate-50 group-hover:bg-cyan-500 group-hover:text-white rounded-xl flex items-center justify-center mb-5 transition-all duration-300">
              <i className={`fa-solid ${dept.icon} text-xl`}></i>
            </div>
            <h3 className="text-lg font-extrabold text-slate-800 group-hover:text-cyan-600 transition-colors tracking-tight">{dept.name}</h3>
            <p className="text-slate-400 text-sm mt-1.5 font-medium leading-tight line-clamp-2">{dept.description}</p>

            <div className="mt-6 flex items-center text-cyan-600 text-[10px] font-black uppercase tracking-widest group-hover:translate-x-1 transition-transform">
              Ver Opções
              <i className="fa-solid fa-arrow-right ml-2 text-[8px]"></i>
            </div>
          </button>
        ))}
      </div>
    </div>
  );

  const renderDepartmentOverview = () => {
    const dept = DEPARTMENTS.find(d => d.id === activeDept);
    if (!dept) return null;

    // Custom configuration for the redesigned cards
    const cardConfig: Record<string, { icon: string, color: string, desc: string }> = {
      'events_assistance': { icon: 'fa-truck-medical', color: 'bg-red-500', desc: 'Solicite guincho ou socorro mecânico.' },
      'events_workshop': { icon: 'fa-calendar-check', color: 'bg-blue-500', desc: 'Marque manutenções e reparos.' },
      'events_delivery': { icon: 'fa-car-side', color: 'bg-green-500', desc: 'Gerencie termos de entrega.' },
      'events_activation': { icon: 'fa-file-contract', color: 'bg-purple-500', desc: 'Visualize termos de serviço.' },
      // Fallbacks for other departments
      'assistance_request': { icon: 'fa-phone-volume', color: 'bg-red-500', desc: 'Acionamento rápido de equipe.' },
      'welcome_membership': { icon: 'fa-handshake', color: 'bg-cyan-500', desc: 'Boas-vindas novos associados.' },
      'welcome_brpower': { icon: 'fa-bolt', color: 'bg-yellow-500', desc: 'Adesão ao plano BR Power.' },
    };

    const getSubmoduleMeta = (id: string) => cardConfig[id] || { icon: 'fa-file-signature', color: 'bg-slate-400', desc: 'Acesse o formulário deste serviço.' };

    return (
      <div className="space-y-10 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center space-x-3">
          <button onClick={() => handleNavigate('home', null)} className="w-10 h-10 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-cyan-600 shadow-sm transition-all">
            <i className="fa-solid fa-arrow-left text-sm"></i>
          </button>
          <div>
            <nav className="flex items-center space-x-2 text-[9px] font-black uppercase tracking-[0.2em] text-slate-400 mb-0.5">
               <span>HUB</span>
               <i className="fa-solid fa-chevron-right text-[7px] opacity-30"></i>
               <span className="text-cyan-600">{dept.name.toUpperCase()}</span>
            </nav>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">Escolha um Serviço</h1>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {dept.submodules.map((sub, idx) => {
            const meta = getSubmoduleMeta(sub.id);
            return (
              <button
                key={sub.id}
                onClick={() => handleNavigate(dept.id, sub.id)}
                style={{ animationDelay: `${idx * 100}ms` }}
                className="relative bg-white rounded-[24px] p-8 text-left shadow-lg shadow-slate-200/50 hover:shadow-2xl hover:shadow-slate-300/60 transition-all duration-300 group hover:-translate-y-1.5 overflow-hidden border border-slate-100 flex flex-col h-full"
              >
                {/* Accent bar on the left */}
                <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${meta.color}`}></div>

                <div className={`w-14 h-14 ${meta.color} text-white rounded-2xl flex items-center justify-center mb-6 shadow-lg shadow-opacity-20 transition-transform group-hover:scale-110 duration-300`}>
                  <i className={`fa-solid ${meta.icon} text-2xl`}></i>
                </div>

                <h3 className="text-lg font-[800] text-slate-800 leading-tight mb-2 group-hover:text-cyan-700 transition-colors">
                  {sub.name}
                </h3>

                <p className="text-slate-500 text-sm font-medium leading-relaxed mb-8 flex-grow">
                  {meta.desc}
                </p>

                <div className="flex items-center text-[10px] font-black uppercase tracking-widest text-slate-400 group-hover:text-cyan-600 transition-colors">
                  Acessar agora
                  <i className="fa-solid fa-chevron-right ml-2 text-[8px] group-hover:translate-x-1 transition-transform"></i>
                </div>
              </button>
            );
          })}
        </div>

        {dept.groups?.map((group) => (
          <div key={group.name} className="mt-12">
            <div className="flex items-center space-x-4 mb-8">
              <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] whitespace-nowrap">{group.name}</h2>
              <div className="h-px w-full bg-slate-200"></div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {group.items.map((sub, idx) => {
                const meta = getSubmoduleMeta(sub.id);
                return (
                  <button
                    key={sub.id}
                    onClick={() => handleNavigate(dept.id, sub.id)}
                    style={{ animationDelay: `${(idx + 4) * 100}ms` }}
                    className="relative bg-white rounded-[24px] p-8 text-left shadow-lg shadow-slate-200/50 hover:shadow-2xl hover:shadow-slate-300/60 transition-all duration-300 group hover:-translate-y-1.5 overflow-hidden border border-slate-100 flex flex-col h-full"
                  >
                    <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${meta.color}`}></div>
                    <div className={`w-14 h-14 ${meta.color} text-white rounded-2xl flex items-center justify-center mb-6 shadow-lg transition-transform group-hover:scale-110 duration-300`}>
                      <i className={`fa-solid ${meta.icon} text-2xl`}></i>
                    </div>
                    <h3 className="text-lg font-[800] text-slate-800 leading-tight mb-2 group-hover:text-cyan-700 transition-colors">
                      {sub.name}
                    </h3>
                    <p className="text-slate-500 text-sm font-medium leading-relaxed mb-8 flex-grow">
                      {meta.desc}
                    </p>
                    <div className="flex items-center text-[10px] font-black uppercase tracking-widest text-slate-400 group-hover:text-cyan-600 transition-colors">
                      Prosseguir
                      <i className="fa-solid fa-chevron-right ml-2 text-[8px] group-hover:translate-x-1 transition-transform"></i>
                    </div>
                  </button>
