    if (Object.values(formData).every(v => !v)) return "";
    const dataLines = Object.entries(formData).filter(([_, v]) => v).map(([k, v]) => `*${k.replace(/_/g, ' ')}:* ${v}`).join('\n');
    const sub = getAllSubmodules().find(s => s.id === activeSubmodule);
