    return `${header}\n\nOlá! Seguem os dados atualizados:\n\n${dataLines}\n\n_BR Clube - Proteção em todo lugar._`;
  };

  const getAllSubmodules = (): Submodule[] => {
    const subs: Submodule[] = [];
    DEPARTMENTS.forEach(d => {
